const task = $.input.taskDescription;
const model = $.input.targetModel || 'Claude';
const format = $.input.outputFormat || 'structured';
const extra = $.input.additionalRequirements || '';

let prompt = 'You are a prompt engineering expert. Create an optimized, production-ready prompt for the following task.\n\n';
prompt += 'TASK DESCRIPTION: ' + task + '\n';
prompt += 'TARGET MODEL: ' + model + '\n';
prompt += 'OUTPUT FORMAT: ' + format + '\n';
if (extra) prompt += 'ADDITIONAL REQUIREMENTS: ' + extra + '\n';
prompt += '\nINSTRUCTIONS:\n';
prompt += '1. Create a clear, structured prompt with:\n';
prompt += '   - System role definition\n';
prompt += '   - Clear task instructions\n';
prompt += '   - Input/output format specification\n';
prompt += '   - 1-2 few-shot examples if helpful\n';
prompt += '   - Edge case handling\n';
prompt += '   - Quality constraints\n';
prompt += '2. Optimize for the target model\n';
prompt += '3. Suggest relevant follow-up questions to refine the task\n';
prompt += '4. Rate the prompt complexity\n\n';
prompt += 'Return ONLY valid JSON:\n';
prompt += '{\n';
prompt += '  "generatedPrompt": "the full optimized prompt text",\n';
prompt += '  "promptTitle": "short title for the prompt",\n';
prompt += '  "systemRole": "the system/role definition used",\n';
prompt += '  "techniques": ["chain-of-thought", "few-shot"],\n';
prompt += '  "estimatedTokens": 500,\n';
prompt += '  "complexity": "simple|moderate|complex",\n';
prompt += '  "refinementQuestions": ["question to improve the prompt"],\n';
prompt += '  "tips": ["model-specific tip 1", "tip 2"],\n';
prompt += '  "alternativeApproach": "brief description of an alternative prompting strategy"\n';
prompt += '}';

return { prompt };

let raw = $.steps.aiGenerate.output || '';
raw = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
try { return JSON.parse(raw); } catch(e) { return { generatedPrompt: raw, promptTitle: 'Generated Prompt', systemRole: '', techniques: [], estimatedTokens: 0, complexity: 'unknown', refinementQuestions: [], tips: [], alternativeApproach: '' }; }

const ai = $.steps.parseAI.output;
const task = $.input.taskDescription;
const model = $.input.targetModel || 'Claude';

const complexEmoji = ai.complexity === 'simple' ? ':large_green_circle:' : ai.complexity === 'complex' ? ':red_circle:' : ':large_yellow_circle:';

const blocks = [];
blocks.push({ type: 'header', text: { type: 'plain_text', text: 'AI Prompt Generator' } });
blocks.push({ type: 'section', fields: [
  { type: 'mrkdwn', text: '*Task:*\n' + task.slice(0, 200) },
  { type: 'mrkdwn', text: '*Target Model:*\n' + model }
] });
blocks.push({ type: 'section', fields: [
  { type: 'mrkdwn', text: '*Complexity:*\n' + complexEmoji + ' ' + (ai.complexity || 'unknown') },
  { type: 'mrkdwn', text: '*Est. Tokens:*\n~' + (ai.estimatedTokens || 'unknown') }
] });
blocks.push({ type: 'divider' });

blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*:page_facing_up: ' + (ai.promptTitle || 'Generated Prompt') + '*' } });

const promptText = (ai.generatedPrompt || 'No prompt generated.').slice(0, 2800);
blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '```' + promptText + '```' } });
blocks.push({ type: 'divider' });

if (ai.techniques && ai.techniques.length > 0) {
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Techniques Used:* ' + ai.techniques.join(', ') } });
}

if (ai.tips && ai.tips.length > 0) {
  let tipText = '*Model-Specific Tips:*\n';
  ai.tips.forEach((t, i) => { tipText += (i + 1) + '. ' + t + '\n'; });
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: tipText.slice(0, 1800) } });
}

if (ai.refinementQuestions && ai.refinementQuestions.length > 0) {
  let qText = '*Refinement Questions:*\n';
  ai.refinementQuestions.forEach((q, i) => { qText += (i + 1) + '. ' + q + '\n'; });
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: qText.slice(0, 1800) } });
}

if (ai.alternativeApproach) {
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Alternative Approach:* ' + ai.alternativeApproach.slice(0, 500) } });
}

blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: 'Powered by Claude AI | Prompt Engineering Agent' }] });

const fallback = 'Generated prompt for: ' + task.slice(0, 100);
return { blocks, fallback };
